        if isinstance(element, util.string_types):
            util.warn_limited(
                "Textual SQL FROM expression %(expr)r should be "
                "explicitly declared as text(%(expr)r), "
                "or use table(%(expr)r) for more specificity",
                {"expr": util.ellipses_string(element)},
            )

